// Build OpenAI-compatible request for Claude Code API
const input = $input.first().json;

const prompt = input.prompt || '';
const system_prompt = input.system_prompt || 'You are a helpful Linux system administrator assistant. Respond concisely and technically.';
const context = input.context || '';

if (!prompt) throw new Error('prompt is required');

const session_id = `claude_${Date.now()}_${Math.random().toString(36).substr(2, 8)}`;

// Build user message (include context if provided)
const userContent = context ? `Context:\n${context}\n\nTask:\n${prompt}` : prompt;

const requestBody = {
  model: 'default',
  messages: [
    {
      role: 'system',
      content: system_prompt
    },
    {
      role: 'user',
      content: userContent
    }
  ],
  max_tokens: 4096,
  temperature: 0.3
};

return [{
  json: {
    request_body: requestBody,
    session_id,
    start_time: Date.now()
  }
}];

// Extract response from Claude API
const apiResponse = $input.first().json;
const buildData = $('🔧 Build Request').first().json;

const execution_time_ms = Date.now() - buildData.start_time;
const session_id = buildData.session_id;

let response_text = '';
let model = 'default';
let tokens_used = 0;
let error = null;

if (apiResponse.error) {
  error = apiResponse.error.message || String(apiResponse.error);
  response_text = `ERROR: ${error}`;
} else if (apiResponse.choices && apiResponse.choices.length > 0) {
  response_text = apiResponse.choices[0].message?.content || '';
  model = apiResponse.model || 'default';
  tokens_used = apiResponse.usage?.total_tokens || 0;
} else if (typeof apiResponse === 'string') {
  response_text = apiResponse;
} else {
  error = 'Unexpected API response format';
  response_text = JSON.stringify(apiResponse);
}

return [{
  json: {
    response_text,
    model,
    tokens_used,
    session_id,
    execution_time_ms,
    error
  }
}];

// _skip=true: kein Gerät dieser Klasse → leere Analyse zurückgeben
const inp = $input.first().json;
return [{ json: {
  session_id: 'skip_' + Date.now(),
  response_text: JSON.stringify({
    hostname: inp.system_name || '__skip__',
    ip: inp.system_ip || null,
    ssh_success: false,
    has_findings: false,
    findings: [],
    error: 'skip_no_devices'
  }),
  model: 'skip',
  tokens_used: 0,
  execution_time_ms: 0,
  error: null
} }];

